def solve(a, k):
    n = len(a)
    dp = [0] * (k + 1)
    for i in range(1, k + 1):
        dp[i] = dp[i - 1]
        for j in range(n):
            if i >= a[j]:
                dp[i] = max(dp[i], dp[i - a[j]] + 1)
    return dp[k]


def main():
    n, k = map(int, input().split())
    a = list(map(int, input().split()))
    print(solve(a, k))


